function Users() {
  const [users, setUsers] = React.useState([]);

  // BUG: fetch runs on every render, the response is never awaited, and nothing is stored
  fetch('https://jsonplaceholder.typicode.com/users');

  return (
    <div style={{ padding: '40px', fontFamily: 'sans-serif', color: '#e0e0e0', background: '#16213e', borderRadius: '8px', maxWidth: '420px', margin: '40px auto' }}>
      <h2 style={{ marginTop: 0 }}>Users</h2>
      <ul>
        {users.map((u, i) => <li key={i}>{u.name}</li>)}
      </ul>
    </div>
  );
}
